// At this point items[0].json is the clean legal JSON object
let legalJson = items[0].json;

// Safety: if it's still wrapped in an array for some reason, unwrap it
if (Array.isArray(legalJson)) {
  legalJson = legalJson[0] || {};
}

const jsonString = JSON.stringify(legalJson, null, 2);

return [
  {
    json: {
      filePath: "/data/uploads/reports/latest.json",
      data: jsonString
    }
  }
];

// Input: full HTTP response from Ollama Analysis
// Real legal JSON is in item.json.response (string)

const item = items[0];
let raw = item.json.response;

// Sometimes Ollama might already return an object/array.
// Handle all cases safely.
if (typeof raw !== 'string') {
  // If it's already JSON, unwrap first element if it's an array
  let parsed = raw;
  if (Array.isArray(parsed)) {
    parsed = parsed[0] || {};
  }
  return [{ json: parsed }];
}

raw = raw.trim();

// If in future you get json ...  wrappers, you can clean here.
// raw = raw.replace(/^json/i, '')
//          .replace(/^/i, '')
//          .replace(/```$/i, '')
//          .trim();

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  throw new Error('Failed to JSON.parse Ollama response: ' + e.message);
}

// If parsed is an array, take the first element
if (Array.isArray(parsed)) {
  parsed = parsed[0] || {};
}

return [{ json: parsed }];
